-- Default packing slip template for J2Commerce 6.0.15
INSERT INTO `#__j2commerce_invoicetemplates` (`title`, `invoice_type`, `orderstatus_id`, `group_id`, `paymentmethod`, `body`, `language`, `enabled`, `ordering`)
VALUES (
    'Default Packing Slip',
    'packingslip',
    '*',
    '*',
    '*',
    '<!-- J2Commerce Packing Slip — Modern Template -->\n<style>\n  @media only screen and (max-width: 620px) {\n    .slip-container { width: 100% !important; }\n    .mobile-padding { padding-left: 16px !important; padding-right: 16px !important; }\n    .mobile-full { width: 100% !important; display: block !important; }\n    .address-col { display: block !important; width: 100% !important; padding: 0 0 12px 0 !important; }\n    .item-img { width: 40px !important; height: 40px !important; }\n  }\n  @media print {\n    body { margin: 0; padding: 0; }\n    .no-print { display: none !important; }\n  }\n</style>\n\n<table width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"background-color: #f8fafc; font-family: Arial, Helvetica, sans-serif;\">\n  <tr>\n    <td align=\"center\" style=\"padding: 20px 10px;\">\n      <table class=\"slip-container\" width=\"600\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"max-width: 600px; width: 100%; background-color: #ffffff;\">\n\n        <!-- Logo Bar -->\n        <tr>\n          <td style=\"padding: 20px 30px; background-color: #ffffff; border-radius: 12px 12px 0 0; text-align: center;\">\n            [IF:STORE_LOGO_URL]\n            <img src=\"[STORE_LOGO_URL]\" alt=\"[SITENAME]\" style=\"display: block; margin: 0 auto; border: 0; height: [LOGO_MAX_HEIGHT]px; width: auto;\" />\n            [/IF:STORE_LOGO_URL]\n            [IFNOT:STORE_LOGO_URL]\n            <span style=\"font-size: 22px; font-weight: bold; color: [ACCENT_COLOR];\">[SITENAME]</span>\n            [/IFNOT:STORE_LOGO_URL]\n          </td>\n        </tr>\n\n        <!-- Packing Slip Header Banner -->\n        <tr>\n          <td style=\"background-color: [ACCENT_COLOR]; padding: 28px 30px; text-align: center;\">\n            <table cellpadding=\"0\" cellspacing=\"0\" border=\"0\" align=\"center\">\n              <tr>\n                <td style=\"width: 50px; height: 50px; background-color: rgba(255,255,255,0.2); border-radius: 50%; text-align: center; vertical-align: middle; font-size: 24px; color: #ffffff;\">\n                  &#128230;\n                </td>\n              </tr>\n            </table>\n            <h1 style=\"margin: 14px 0 4px 0; font-size: 24px; font-weight: bold; color: #ffffff; text-transform: uppercase; letter-spacing: 1px;\">Packing Slip</h1>\n            <p style=\"margin: 0; font-size: 14px; color: rgba(255,255,255,0.85);\">\n              Order #[ORDERID] &bull; [ORDERDATE]\n            </p>\n          </td>\n        </tr>\n\n        <!-- Ship To & Order Info Cards -->\n        <tr>\n          <td class=\"mobile-padding\" style=\"padding: 20px 20px 0 20px;\">\n            <table width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\">\n              <tr>\n                <td class=\"address-col\" style=\"width: 60%; vertical-align: top; padding-right: 8px;\">\n                  <table width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"background-color: #ffffff; border: 1px solid #e5e7eb; border-radius: 10px;\">\n                    <tr>\n                      <td style=\"padding: 14px 18px; border-bottom: 1px solid #f3f4f6; font-size: 13px; font-weight: bold; color: #6b7280; text-transform: uppercase; letter-spacing: 0.5px;\">Ship To</td>\n                    </tr>\n                    <tr>\n                      <td style=\"padding: 14px 18px; font-size: 14px; color: #1f2937; line-height: 1.6;\">\n                        <strong style=\"font-size: 15px;\">[SHIPPING_FIRSTNAME] [SHIPPING_LASTNAME]</strong>\n                        [IF:SHIPPING_COMPANY]<br />[SHIPPING_COMPANY][/IF:SHIPPING_COMPANY]<br />\n                        [SHIPPING_ADDRESS_1]\n                        [IF:SHIPPING_ADDRESS_2]<br />[SHIPPING_ADDRESS_2][/IF:SHIPPING_ADDRESS_2]<br />\n                        [SHIPPING_CITY], [SHIPPING_STATE] [SHIPPING_ZIP]<br />\n                        [SHIPPING_COUNTRY]\n                        [IF:SHIPPING_PHONE]<br />&#128222; [SHIPPING_PHONE][/IF:SHIPPING_PHONE]\n                      </td>\n                    </tr>\n                  </table>\n                </td>\n                <td class=\"address-col\" style=\"width: 40%; vertical-align: top; padding-left: 8px;\">\n                  <table width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"background-color: #ffffff; border: 1px solid #e5e7eb; border-radius: 10px;\">\n                    <tr>\n                      <td style=\"padding: 14px 18px; border-bottom: 1px solid #f3f4f6; font-size: 13px; font-weight: bold; color: #6b7280; text-transform: uppercase; letter-spacing: 0.5px;\">Order Details</td>\n                    </tr>\n                    <tr>\n                      <td style=\"padding: 14px 18px; font-size: 13px; color: #1f2937; line-height: 1.8;\">\n                        <strong>Order:</strong> #[ORDERID]<br />\n                        <strong>Date:</strong> [ORDERDATE]<br />\n                        <strong>Status:</strong> [ORDERSTATUS]\n                        [IF:SHIPPING_METHOD]<br /><strong>Ship via:</strong> [SHIPPING_METHOD][/IF:SHIPPING_METHOD]\n                        [IF:SHIPPING_TRACKING_ID]<br /><strong>Tracking:</strong> [SHIPPING_TRACKING_ID][/IF:SHIPPING_TRACKING_ID]\n                      </td>\n                    </tr>\n                  </table>\n                </td>\n              </tr>\n            </table>\n          </td>\n        </tr>\n\n        <!-- Items Card (NO PRICES) -->\n        <tr>\n          <td class=\"mobile-padding\" style=\"padding: 16px 20px;\">\n            <table width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"background-color: #ffffff; border: 1px solid #e5e7eb; border-radius: 10px; overflow: hidden;\">\n              <tr>\n                <td colspan=\"4\" style=\"padding: 16px 20px; border-bottom: 1px solid #f3f4f6;\">\n                  <span style=\"font-size: 15px; font-weight: bold; color: #1f2937;\">Items to Pack</span>\n                </td>\n              </tr>\n              <tr>\n                <td style=\"padding: 10px 20px; font-size: 11px; font-weight: bold; color: #9ca3af; text-transform: uppercase; letter-spacing: 0.5px;\" colspan=\"2\">Product</td>\n                <td style=\"padding: 10px 10px; font-size: 11px; font-weight: bold; color: #9ca3af; text-transform: uppercase; letter-spacing: 0.5px; text-align: center; width: 50px;\">Qty</td>\n                <td style=\"padding: 10px 20px; font-size: 11px; font-weight: bold; color: #9ca3af; text-transform: uppercase; letter-spacing: 0.5px; text-align: center; width: 70px;\">Packed &#10003;</td>\n              </tr>\n              [ITEMS_LOOP]\n              <tr>\n                <td style=\"padding: 12px 0 12px 20px; border-top: 1px solid #f3f4f6; vertical-align: top; width: 60px;\">\n                  [IF:ITEM_IMAGE]\n                  <img src=\"[ITEM_IMAGE]\" alt=\"[ITEM_NAME]\" width=\"50\" height=\"50\" class=\"item-img\" style=\"border-radius: 6px; object-fit: cover; display: block; border: 1px solid #f3f4f6;\" />\n                  [/IF:ITEM_IMAGE]\n                  [IFNOT:ITEM_IMAGE]\n                  <table cellpadding=\"0\" cellspacing=\"0\" border=\"0\"><tr><td style=\"width: 50px; height: 50px; background-color: #f3f4f6; border-radius: 6px; text-align: center; vertical-align: middle; font-size: 20px; color: #d1d5db;\">&#128230;</td></tr></table>\n                  [/IFNOT:ITEM_IMAGE]\n                </td>\n                <td style=\"padding: 12px 10px; border-top: 1px solid #f3f4f6; vertical-align: top;\">\n                  <span style=\"font-size: 14px; font-weight: 600; color: #1f2937;\">[ITEM_NAME]</span>\n                  [IF:ITEM_SKU]<br /><span style=\"font-size: 12px; color: #9ca3af;\">SKU: [ITEM_SKU]</span>[/IF:ITEM_SKU]\n                  [IF:ITEM_OPTIONS]<br /><span style=\"font-size: 12px; color: #6b7280;\">[ITEM_OPTIONS]</span>[/IF:ITEM_OPTIONS]\n                  [IF:ITEM_WEIGHT]<br /><span style=\"font-size: 12px; color: #9ca3af;\">Weight: [ITEM_WEIGHT]</span>[/IF:ITEM_WEIGHT]\n                </td>\n                <td style=\"padding: 12px 10px; border-top: 1px solid #f3f4f6; text-align: center; vertical-align: top; font-size: 18px; font-weight: bold; color: #1f2937;\">[ITEM_QTY]</td>\n                <td style=\"padding: 12px 20px; border-top: 1px solid #f3f4f6; text-align: center; vertical-align: top;\">\n                  <table cellpadding=\"0\" cellspacing=\"0\" border=\"0\" align=\"center\"><tr><td style=\"width: 24px; height: 24px; border: 2px solid #d1d5db; border-radius: 4px; background-color: #ffffff;\"></td></tr></table>\n                </td>\n              </tr>\n              [/ITEMS_LOOP]\n              <tr>\n                <td colspan=\"4\" style=\"padding: 14px 20px; background-color: #f9fafb; border-top: 1px solid #e5e7eb;\">\n                  <table width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\">\n                    <tr>\n                      <td style=\"font-size: 13px; font-weight: bold; color: #6b7280;\">Total Weight</td>\n                      <td style=\"font-size: 13px; font-weight: bold; color: #1f2937; text-align: right;\">[SHIPPING_TOTAL_WEIGHT]</td>\n                    </tr>\n                  </table>\n                </td>\n              </tr>\n            </table>\n          </td>\n        </tr>\n\n        <!-- Customer Note -->\n        <tr>\n          <td class=\"mobile-padding\" style=\"padding: 0;\">\n            [IF:CUSTOMER_NOTE]\n            <table width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\">\n              <tr>\n                <td style=\"padding: 0 20px 16px 20px;\">\n                  <table width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"background-color: #fffbeb; border: 1px solid #fde68a; border-radius: 10px;\">\n                    <tr>\n                      <td style=\"padding: 14px 18px; font-size: 13px; font-weight: bold; color: #92400e; text-transform: uppercase; letter-spacing: 0.5px;\">&#9888; Customer Note</td>\n                    </tr>\n                    <tr>\n                      <td style=\"padding: 0 18px 14px 18px; font-size: 14px; color: #78350f; line-height: 1.5;\">[CUSTOMER_NOTE]</td>\n                    </tr>\n                  </table>\n                </td>\n              </tr>\n            </table>\n            [/IF:CUSTOMER_NOTE]\n          </td>\n        </tr>\n\n        <!-- Packed By / Signature Section -->\n        <tr>\n          <td class=\"mobile-padding\" style=\"padding: 0 20px 20px 20px;\">\n            <table width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"background-color: #f9fafb; border: 1px solid #e5e7eb; border-radius: 10px;\">\n              <tr>\n                <td style=\"padding: 14px 18px; border-bottom: 1px solid #e5e7eb; font-size: 13px; font-weight: bold; color: #6b7280; text-transform: uppercase; letter-spacing: 0.5px;\">Fulfillment</td>\n              </tr>\n              <tr>\n                <td style=\"padding: 18px;\">\n                  <table width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\">\n                    <tr>\n                      <td style=\"width: 50%; padding: 0 10px 0 0; vertical-align: bottom;\">\n                        <span style=\"font-size: 12px; font-weight: bold; color: #6b7280; text-transform: uppercase;\">Packed by</span>\n                        <div style=\"margin-top: 8px; border-bottom: 1px solid #d1d5db; min-height: 28px;\"></div>\n                      </td>\n                      <td style=\"width: 25%; padding: 0 10px; vertical-align: bottom;\">\n                        <span style=\"font-size: 12px; font-weight: bold; color: #6b7280; text-transform: uppercase;\">Date</span>\n                        <div style=\"margin-top: 8px; border-bottom: 1px solid #d1d5db; min-height: 28px;\"></div>\n                      </td>\n                      <td style=\"width: 25%; padding: 0 0 0 10px; vertical-align: bottom;\">\n                        <span style=\"font-size: 12px; font-weight: bold; color: #6b7280; text-transform: uppercase;\">Boxes</span>\n                        <div style=\"margin-top: 8px; border-bottom: 1px solid #d1d5db; min-height: 28px;\"></div>\n                      </td>\n                    </tr>\n                  </table>\n                </td>\n              </tr>\n            </table>\n          </td>\n        </tr>\n\n        <!-- Footer -->\n        <tr>\n          <td style=\"padding: 18px 30px; background-color: #ffffff; border-radius: 0 0 12px 12px; border-top: 1px solid #f3f4f6; text-align: center;\">\n            <p style=\"font-size: 12px; color: #9ca3af; margin: 0;\">\n              &copy; [CURRENT_YEAR] [SITENAME] &bull; [SITEURL]\n            </p>\n          </td>\n        </tr>\n\n      </table>\n    </td>\n  </tr>\n</table>',
    '*',
    1,
    99
);
